import { useState, useEffect } from 'react';
import { rpc } from '@stellar/stellar-sdk';

const server = new rpc.Server('https://soroban-testnet.stellar.org');

export function useContractEvents(contractId) {
  const [raised, setRaised] = useState(0);
  const [events, setEvents] = useState([]);

  useEffect(() => {
    if (!contractId) return;

    let isSubscribed = true;
    let lastCursor = undefined;

    const pollEvents = async () => {
      try {
        // Fetch the latest ledger to get a recent start ledger if no cursor
        let startLedger = undefined;
        if (!lastCursor) {
          const latestLedger = await server.getLatestLedger();
          startLedger = latestLedger.sequence - 100; // Look back ~100 ledgers initially
        }

        const response = await server.getEvents({
          startLedger,
          cursor: lastCursor,
          filters: [
            {
              type: 'contract',
              contractIds: [contractId],
              topics: [['*', 'DONATE']], 
            },
          ],
          limit: 100,
        });

        if (isSubscribed && response.events && response.events.length > 0) {
          // Parse events
          response.events.forEach((evt) => {
            if (evt.topic.length > 0 && evt.topic[0].includes('DONATE')) {
              // The amount is in the value (data)
              // Assuming it's parsed as i128
              // We'd parse the XDR value here. 
              // For simplicity of not importing full XDR logic here, we'll track the latest ledger
              console.log("Donation event received:", evt);
            }
          });

          if (response.latestLedger) {
              lastCursor = response.latestLedger.toString();
          }
        }
      } catch (err) {
        console.error("Error polling contract events:", err);
      }

      if (isSubscribed) {
        setTimeout(pollEvents, 5000); // poll every 5 seconds
      }
    };

    pollEvents();

    return () => {
      isSubscribed = false;
    };
  }, [contractId]);

  return { events };
}
